<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
  }
  h1 {
    margin-bottom: 16px;
    font-size: 1.6rem;
    color: #a0c4ff;
    letter-spacing: 1px;
  }
  #controls {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
  }
  #controls button {
    padding: 10px 28px;
    font-size: 1rem;
    font-weight: 600;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s, transform 0.1s;
  }
  #controls button:active { transform: scale(0.96); }
  #sort {
    background: #4361ee;
    color: #fff;
  }
  #sort:hover { background: #3a56d4; }
  #sort:disabled { background: #2a3a6a; color: #667; cursor: default; }
  #shuffle {
    background: #f72585;
    color: #fff;
  }
  #shuffle:hover { background: #d41e72; }
  #reset {
    background: #4cc9f0;
    color: #1a1a2e;
  }
  #reset:hover { background: #3ab8de; }
  #bars {
    display: flex;
    align-items: flex-end;
    justify-content: center;
    width: 90%;
    max-width: 900px;
    height: 420px;
    background: #16213e;
    border-radius: 10px;
    padding: 10px 6px;
    gap: 2px;
    border: 1px solid #0f3460;
  }
  .bar {
    flex: 1;
    min-width: 4px;
    max-width: 40px;
    background: #4cc9f0;
    border-radius: 3px 3px 0 0;
    transition: height 0.08s ease, background 0.15s ease;
    position: relative;
  }
  .bar.comparing {
    background: #f72585;
  }
  .bar.sorted {
    background: #4361ee;
  }
  .bar.swapping {
    background: #ff9e00;
  }
  #status {
    margin-top: 14px;
    font-size: 0.95rem;
    color: #888;
    height: 1.2em;
  }
</style>
</head>
<body>

<h1>Sorting Visualizer</h1>

<div id="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>

<div id="bars"></div>
<div id="status"></div>

<script>
(function() {
  const barsContainer = document.getElementById('bars');
  const sortBtn = document.getElementById('sort');
  const shuffleBtn = document.getElementById('shuffle');
  const resetBtn = document.getElementById('reset');
  const statusEl = document.getElementById('status');

  let currentArray = [];
  let sortState = null;   // { i, j, phase, done }
  let sorting = false;
  let animTimer = null;

  const DEFAULT_ARRAY = [45, 23, 78, 12, 56, 89, 34, 67, 9, 41, 55, 30, 72, 18, 63];
  const NUM_BARS = 20;

  function randomArray(n) {
    const arr = [];
    for (let i = 0; i < n; i++) arr.push(Math.floor(Math.random() * 95) + 5);
    return arr;
  }

  function renderBars(highlights) {
    barsContainer.innerHTML = '';
    const maxVal = Math.max(...currentArray, 1);
    const barCount = currentArray.length;
    for (let i = 0; i < barCount; i++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      const h = (currentArray[i] / maxVal) * 380;
      bar.style.height = h + 'px';
      if (highlights && highlights[i]) {
        bar.classList.add(highlights[i]);
      }
      bar.title = currentArray[i];
      barsContainer.appendChild(bar);
    }
  }

  function getHighlights() {
    const h = {};
    if (!sorting || !sortState) return h;
    if (sortState.phase === 'compare') {
      h[sortState.j] = 'comparing';
      h[sortState.j + 1] = 'comparing';
    }
    if (sortState.phase === 'swap') {
      h[sortState.j] = 'swapping';
      h[sortState.j + 1] = 'swapping';
    }
    if (sortState.phase === 'done') {
      for (let k = sortState.i; k < currentArray.length; k++) {
        h[k] = 'sorted';
      }
    }
    return h;
  }

  function initArray(arr) {
    currentArray = arr.slice();
    sortState = null;
    sorting = false;
    if (animTimer) { clearInterval(animTimer); animTimer = null; }
    sortBtn.disabled = false;
    renderBars();
    statusEl.textContent = '';
  }

  function startSort() {
    if (sorting) return;
    sorting = true;
    sortBtn.disabled = true;
    sortState = {
      i: 0,
      j: 0,
      phase: 'compare',
      done: false
    };
    statusEl.textContent = 'Sorting...';
    animTimer = setInterval(stepSort, 60);
  }

  function stepSort() {
    if (!sorting || !sortState || sortState.done) {
      if (animTimer) { clearInterval(animTimer); animTimer = null; }
      sorting = false;
      sortBtn.disabled = false;
      statusEl.textContent = 'Sorted!';
      renderBars();
      return;
    }

    const n = currentArray.length;
    if (sortState.i >= n - 1) {
      sortState.done = true;
      renderBars(getHighlights());
      if (animTimer) { clearInterval(animTimer); animTimer = null; }
      sorting = false;
      sortBtn.disabled = false;
      statusEl.textContent = 'Sorted!';
      return;
    }

    if (sortState.j >= n - 1 - sortState.i) {
      sortState.j = 0;
      sortState.i++;
      sortState.phase = 'compare';
      renderBars(getHighlights());
      return;
    }

    if (sortState.phase === 'compare') {
      sortState.phase = 'check';
      renderBars(getHighlights());
      return;
    }

    if (sortState.phase === 'check') {
      if (currentArray[sortState.j] > currentArray[sortState.j + 1]) {
        sortState.phase = 'swap';
        renderBars(getHighlights());
        return;
      } else {
        sortState.j++;
        sortState.phase = 'compare';
        renderBars(getHighlights());
        return;
      }
    }

    if (sortState.phase === 'swap') {
      const tmp = currentArray[sortState.j];
      currentArray[sortState.j] = currentArray[sortState.j + 1];
      currentArray[sortState.j + 1] = tmp;
      sortState.j++;
      sortState.phase = 'compare';
      renderBars(getHighlights());
      return;
    }
  }

  // ---- Programmatic API ----
  window.viz = {
    array: function() {
      return currentArray.slice();
    },
    setArray: function(a) {
      if (!Array.isArray(a) || a.length === 0) return;
      currentArray = a.map(Number);
      sortState = null;
      sorting = false;
      if (animTimer) { clearInterval(animTimer); animTimer = null; }
      sortBtn.disabled = false;
      renderBars();
      statusEl.textContent = '';
    },
    sortStep: function() {
      if (sorting) return false;

      // Initialize sort if not already
      if (!sortState) {
        sortState = {
          i: 0,
          j: 0,
          phase: 'compare',
          done: false
        };
      }

      const n = currentArray.length;

      // Check if already sorted
      if (sortState.i >= n - 1) {
        sortState.done = true;
        renderBars(getHighlights());
        return true;
      }

      if (sortState.j >= n - 1 - sortState.i) {
        sortState.j = 0;
        sortState.i++;
        sortState.phase = 'compare';
        renderBars(getHighlights());
        return false;
      }

      if (sortState.phase === 'compare') {
        sortState.phase = 'check';
        renderBars(getHighlights());
        return false;
      }

      if (sortState.phase === 'check') {
        if (currentArray[sortState.j] > currentArray[sortState.j + 1]) {
          sortState.phase = 'swap';
          renderBars(getHighlights());
          return false;
        } else {
          sortState.j++;
          sortState.phase = 'compare';
          renderBars(getHighlights());
          return false;
        }
      }

      if (sortState.phase === 'swap') {
        const tmp = currentArray[sortState.j];
        currentArray[sortState.j] = currentArray[sortState.j + 1];
        currentArray[sortState.j + 1] = tmp;
        sortState.j++;
        sortState.phase = 'compare';
        renderBars(getHighlights());
        return false;
      }

      return false;
    },
    sorted: function() {
      for (let i = 1; i < currentArray.length; i++) {
        if (currentArray[i] < currentArray[i - 1]) return false;
      }
      return true;
    }
  };

  // ---- Button handlers ----
  sortBtn.addEventListener('click', function() {
    if (sorting) return;
    startSort();
  });

  shuffleBtn.addEventListener('click', function() {
    const shuffled = randomArray(NUM_BARS);
    // Make sure it's not already sorted
    let isSorted = true;
    for (let i = 1; i < shuffled.length; i++) {
      if (shuffled[i] < shuffled[i - 1]) { isSorted = false; break; }
    }
    if (isSorted) {
      // Swap two elements
      const idx = Math.floor(Math.random() * (shuffled.length - 1));
      const tmp = shuffled[idx];
      shuffled[idx] = shuffled[idx + 1];
      shuffled[idx + 1] = tmp;
    }
    window.viz.setArray(shuffled);
  });

  resetBtn.addEventListener('click', function() {
    window.viz.setArray(DEFAULT_ARRAY);
  });

  // Initialize
  window.viz.setArray(randomArray(NUM_BARS));
})();
</script>

</body>
</html>
